import{_ as e,a as t,b as d,c as r}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as n,o as c,c as i,a2 as p}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Redundant Backup และ Read Source Switching","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/Other/redundant-backup-and-read-source.md","filePath":"th-TH/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),l={name:"th-TH/Other/redundant-backup-and-read-source.md"};function u(s,a,h,o,b,k){return c(),i("div",null,[...a[0]||(a[0]=[p('<h1 id="redundant-backup-และ-read-source-switching" tabindex="-1">Redundant Backup และ Read Source Switching <a class="header-anchor" href="#redundant-backup-และ-read-source-switching" aria-label="Permalink to &quot;Redundant Backup และ Read Source Switching&quot;">​</a></h1><p>Redundant backup เก็บ extra copy ของ file ที่ upload แล้ว</p><p>ทั้ง primary file และ backup file ใช้เป็น read sources ได้ Visitors โดยทั่วไปจะไม่เห็นความต่าง ต่างกันแค่ storage channel ใด serve file</p><h2 id="redundant-backup-ทําอะไรได้บ้าง" tabindex="-1">Redundant Backup ทำอะไรได้บ้าง <a class="header-anchor" href="#redundant-backup-ทําอะไรได้บ้าง" aria-label="Permalink to &quot;Redundant Backup ทำอะไรได้บ้าง&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Store an extra copy</td><td>Back up files ไปยัง upload channel อื่นเพื่อลด risk หาก channel เดียวล้มเหลว</td></tr><tr><td>Switch read source</td><td>หลัง backup สำเร็จ สลับ file reads ระหว่าง primary channel และ backup channel</td></tr><tr><td>Single-file backup</td><td>Back up file เดียวจาก file details page</td></tr><tr><td>Batch backup</td><td>เลือกหลาย files ใน admin page แล้ว back up พร้อมกัน</td></tr><tr><td>Global redundant backup</td><td>Back up files ตาม folder จาก Other Settings</td></tr></tbody></table><h2 id="redundant-backup-entry" tabindex="-1">Redundant Backup Entry <a class="header-anchor" href="#redundant-backup-entry" aria-label="Permalink to &quot;Redundant Backup Entry&quot;">​</a></h2><p>เปิด:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+e+'" alt="Redundant backup" loading="lazy"></p><p>Entry นี้เหมาะกับการเพิ่ม backups ให้ folder หรือ files ทั้งหมดแบบ bulk</p><p>Backup channel เลือกเองได้ หรือเลือก automatic switching ให้ ImgBed หา suitable backup channel</p><h2 id="backup-จาก-file-details" tabindex="-1">Backup จาก File Details <a class="header-anchor" href="#backup-จาก-file-details" aria-label="Permalink to &quot;Backup จาก File Details&quot;">​</a></h2><p>เปิด file details page ใน admin panel แล้วคลิก backup</p><p><img src="'+t+'" alt="Backup in file details" loading="lazy"></p><p>เหมาะกับการ back up important file หนึ่งไฟล์แบบ on demand</p><p>หลัง backup สำเร็จ file details page จะแสดง available read sources</p><h2 id="batch-backup-by-selection" tabindex="-1">Batch Backup by Selection <a class="header-anchor" href="#batch-backup-by-selection" aria-label="Permalink to &quot;Batch Backup by Selection&quot;">​</a></h2><p>ใน admin panel เลือกหลาย files แล้ว run batch backup</p><p><img src="'+d+'" alt="Batch backup" loading="lazy"></p><p>เหมาะกับการ process files เป็นกลุ่ม</p><p>Selection backup, file details backup และ redundant backup ใต้ Other Settings ใช้ backup system เดียวกัน เป็นเพียง entry points คนละจุด</p><h2 id="switch-read-source-หลัง-backup" tabindex="-1">Switch Read Source หลัง Backup <a class="header-anchor" href="#switch-read-source-หลัง-backup" aria-label="Permalink to &quot;Switch Read Source หลัง Backup&quot;">​</a></h2><p>หลัง backup complete file details page ให้ switch read source ได้:</p><table tabindex="0"><thead><tr><th>Read Source</th><th>Description</th></tr></thead><tbody><tr><td>Primary channel</td><td>Read จาก original upload channel</td></tr><tr><td>Backup channel</td><td>Read จาก backup channel</td></tr></tbody></table><p><img src="'+r+'" alt="Switch read source after backup" loading="lazy"></p><p>Visitors ไม่จำเป็นต้องรู้ว่า file serve จาก primary หรือ backup channel</p><p>Read source ที่คุณเลือกจะกลายเป็น preferred source สำหรับ file access ภายหลัง</p><h2 id="เมื่อไร-backup-จะถูก-skip" tabindex="-1">เมื่อไร Backup จะถูก Skip <a class="header-anchor" href="#เมื่อไร-backup-จะถูก-skip" aria-label="Permalink to &quot;เมื่อไร Backup จะถูก Skip&quot;">​</a></h2><p>Cases ต่อไปนี้จะถูก skip ระหว่าง backup ไม่ใช่ errors</p><table tabindex="0"><thead><tr><th>Case</th><th>Why It Is Skipped</th></tr></thead><tbody><tr><td>Already backed up</td><td>File ที่มี backup แล้วจะไม่ back up ซ้ำ</td></tr><tr><td>Primary และ backup channels เหมือนกัน</td><td>Backup ต้องเก็บใน channel อื่นจึงจะมีความหมาย</td></tr><tr><td>No usable backup channel</td><td>ไม่มี alternative channel ที่เหมาะสม</td></tr></tbody></table><p>สรุป: backups ต้องไปยัง channel อื่น และ files ที่ backed up แล้วจะไม่กินพื้นที่เพิ่มซ้ำ</p><h2 id="primary-channel-vs-backup-channel" tabindex="-1">Primary Channel vs Backup Channel <a class="header-anchor" href="#primary-channel-vs-backup-channel" aria-label="Permalink to &quot;Primary Channel vs Backup Channel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td>Primary channel</td><td>Channel ที่ใช้ตอน file ถูก upload ครั้งแรก</td></tr><tr><td>Backup channel</td><td>Channel ที่เก็บ redundant copy</td></tr><tr><td>Primary read source</td><td>File กำลัง read จาก primary channel</td></tr><tr><td>Backup read source</td><td>File กำลัง read จาก backup channel</td></tr></tbody></table><p>Primary และ backup read sources มี user-facing behavior เหมือนกัน</p><p>ตราบใดที่ backup file available images, videos และ download links จะยังทำงานหลัง switch ไป backup read source</p><h2 id="เมื่อ-file-ถูก-delete" tabindex="-1">เมื่อ File ถูก Delete <a class="header-anchor" href="#เมื่อ-file-ถูก-delete" aria-label="Permalink to &quot;เมื่อ File ถูก Delete&quot;">​</a></h2><p>เมื่อ delete file ImgBed จะ delete ทั้ง primary file และ backup file</p>',37)])])}const g=n(l,[["render",u]]);export{y as __pageData,g as default};
